local GUICheckMoneyContent = class("GUICheckMoneyContent", IGUILayout)

function GUICheckMoneyContent:onLoad()
    self.tvCurrencyTip = self:getChildWindow("CheckMoneyContent-Currency-Tip", GUIType.StaticText)
    self.ivCurrencyIcon = self:getChildWindow("CheckMoneyContent-Currency-Icon", GUIType.StaticImage)
    self.tvCurrencyNum = self:getChildWindow("CheckMoneyContent-Currency-Num", GUIType.StaticText)
    self.tvContentText = self:getChildWindow("CheckMoneyContent-Content-Text", GUIType.StaticText)
    self.tvCurrencyTip:SetText(Lang:getString("gui_tip_need_currency"))
end

CheckMoneyContent = buildCustomDialogContent(GUICheckMoneyContent, "CheckMoneyContent.json")

function CheckMoneyContent:setCurrencyInfo(icon, count)
    self.tvCurrencyTip:SetText(Lang:getString("gui_tip_need_currency"))
    self.ivCurrencyIcon:SetImage(icon)
    self.tvCurrencyNum:SetText(tostring(count))
end

function CheckMoneyContent:setContentText(text)
    self.tvContentText:SetText(text)
end

function CheckMoneyContent:setCurrencyTip(text)
    self.tvCurrencyTip:SetText(text)
end

function CheckMoneyContent:setCurrencyNum(text)
    self.tvCurrencyNum:SetText(tostring(text))
end

function CheckMoneyContent:setTextColor(color)
    self.tvCurrencyTip:SetTextColor(color)
    self.tvContentText:SetTextColor(color)
    self.tvCurrencyNum:SetTextColor(color)
end